previewCss:
.darma-loader-darma-custom-670 {color: var(--loader-color, #333333);
  --loader-secondary-color: #94a3b8;
  --loader-bg: #f8fafc;

  --dim: 3rem;
  width: var(--dim);
  height: var(--dim);
  position: relative;
  animation: darma-loader-darma-custom-670-spin988 2s linear infinite;
}

.darma-loader-darma-custom-670 .darma-loader-darma-custom-670-circle {
  --color: #333;
  --dim: 1.2rem;
  width: var(--dim);
  height: var(--dim);
  background-color: var(--color);
  border-radius: 50%;
  position: absolute;
}

.darma-loader-darma-custom-670 .darma-loader-darma-custom-670-circle:nth-child(1) {
  top: 0;
  left: 0;
}

.darma-loader-darma-custom-670 .darma-loader-darma-custom-670-circle:nth-child(2) {
  top: 0;
  right: 0;
}

.darma-loader-darma-custom-670 .darma-loader-darma-custom-670-circle:nth-child(3) {
  bottom: 0;
  left: 0;
}

.darma-loader-darma-custom-670 .darma-loader-darma-custom-670-circle:nth-child(4) {
  bottom: 0;
  right: 0;
}

@keyframes darma-loader-darma-custom-670-spin988 {
  0% {
    transform: scale(1) rotate(0);
  }

  20%, 25% {
    transform: scale(1.3) rotate(90deg);
  }

  45%, 50% {
    transform: scale(1) rotate(180deg);
  }

  70%, 75% {
    transform: scale(1.3) rotate(270deg);
  }

  95%, 100% {
    transform: scale(1) rotate(360deg);
  }
}

